SELECT [Sales Header].[Document Type], [Sales Line].[Document No_] AS OrdineNumero, [Sales Line].[Line No_] AS OrdineRiga, [Sales Line].Type, Val([quantity])-Nz([TOTALEASSORTIMENTICOPERTI]) AS assortmentQty, Val([No_ of pairs])-Nz([TOTALEPAIACOPERTE]) AS pairsQty, "INEV" AS statusRiga, [Sales Header].[Selling Season Code] AS [Season Code], [Sales Line].[Delete Reason], [Sales Header].[Location Code] AS SalesLocation
FROM ([Sales Line] RIGHT JOIN [Sales Header] ON [Sales Line].[Document No_] = [Sales Header].No_) LEFT JOIN [VenditeEPrenotazioni-CalcoloTotaleCoperto_TABELLA] ON ([Sales Line].[Line No_] = [VenditeEPrenotazioni-CalcoloTotaleCoperto_TABELLA].OrdineRiga) AND ([Sales Line].[Document No_] = [VenditeEPrenotazioni-CalcoloTotaleCoperto_TABELLA].OrdineNumero)
WHERE ((([Sales Header].[Document Type])=1) AND (([Sales Line].Type)=20) AND ((Val([quantity])-Nz([TOTALEASSORTIMENTICOPERTI]))<>0) AND (([Sales Header].[Selling Season Code])=[forms]![principale]![filtroStagioneprenotazioni]) AND (([Sales Line].[Delete Reason])=""));

